"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[36601],{37491:e=>{e.exports=JSON.parse('{"tag":{"label":"aoe","permalink":"/dst-api-webdocs/docs/tags/aoe","allTagsPath":"/dst-api-webdocs/docs/tags","count":11,"items":[{"id":"game-scripts/components/aoespell","title":"Aoespell","description":"Manages casting and validation logic for area-of-effect (AoE) spells in DST, integrating with targeting, spellbook, inventory, and world constraint systems.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoespell"},{"id":"game-scripts/components/aoetargeting","title":"Aoetargeting","description":"Manages AOE (area-of-effect) targeting state and visual feedback for deployable items, including reticule management, range validation, and FX spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoetargeting"},{"id":"game-scripts/components/aoeweapon_base","title":"Aoeweapon Base","description":"Provides shared behavior for area-of-effect weapons that can destroy workables, pick pickables, or attack combat targets.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoeweapon_base"},{"id":"game-scripts/components/aoeweapon_leap","title":"Aoeweapon Leap","description":"Enables a leap-based area-of-effect weapon attack that hits multiple targets in a radius and optionally tosses physics-enabled entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoeweapon_leap"},{"id":"game-scripts/components/aoeweapon_lunge","title":"Aoeweapon Lunge","description":"Implements a forward-lunge area-of-effect weapon mechanic that calculates directional hit and toss zones, then triggers OnHit/OnToss callbacks with physics-aware overlap checks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoeweapon_lunge"},{"id":"game-scripts/prefabs/blowdart_lava","title":"Blowdart Lava","description":"A specialized blowdart item that launches explosive lava projectiles, using AOE targeting with custom reticule behavior and visual trails.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart_lava"},{"id":"game-scripts/prefabs/healingstaff","title":"Healingstaff","description":"A ranged weapon prefab that provides AOE targeting support and projectile casting functionality in DST\'s Lava Arena event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/healingstaff"},{"id":"game-scripts/prefabs/lavaarena_firebomb","title":"Lavaarena Firebomb","description":"Provides a throwable weapon for the Lava Arena event that projects an AOE targeting reticule and fires projectiles on use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_firebomb"},{"id":"game-scripts/prefabs/ruinsnightmare_horn_attack","title":"Ruinsnightmare Horn Attack","description":"Handles the behavior and physics of a fast-moving, AoE-damaging projectile created by the Ruins Nightmare boss attack, including collision detection, speed interpolation, and damage application.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruinsnightmare_horn_attack"},{"id":"game-scripts/prefabs/warg_mutated_fx","title":"Warg Mutated Fx","description":"Manages animated fire and ember effects used by the mutated warg\u2019s flamethrower attack, handling collision, temperature damage, visual fading, and particle reuse.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/warg_mutated_fx"},{"id":"game-scripts/prefabs/winona_catapult_projectile","title":"Winona Catapult Projectile","description":"Handles the physics, targeting, and area-of-effect effects of a Winona catapult projectile upon impact, including elemental damage, terrain destruction, trap spawning, and object tossing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_catapult_projectile"}],"unlisted":false}}')}}]);